export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "當李杰回到帳篷附近時，他驚訝地發現恵美已經醒了。她坐在帳篷外的草地上,面前有一堆小小的營火,上面架著一個簡單的鐵鍋,正咕嘟咕嘟地冒著熱氣。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "恵美看起來精神不錯,臉上帶著淡淡的笑容。她的頭髮有些凌亂,但在晨光——不,應該說月光下,反而顯得格外可愛。她正用木勺攪拌著鍋裡的食物,專注的樣子讓李杰不忍心打擾。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個年輕的精靈女孩蹲在旁邊,正在教恵美如何控制火候。兩人愉快地交談著,氣氛很融洽。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(抬頭看到李杰,臉上綻放出燦爛的笑容) 李杰先生!你回來啦!" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(走過去,有些驚訝) 妳醒了?這是...妳在做飯?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(點點頭,有些不好意思) 嗯...醒來發現你不在,就想說做點吃的。這位精靈姐姐幫我生了火,還教我怎麼煮。" },
    { characterId: CharacterId.Elf, character: "精靈女孩", dialogue: "(對李杰微笑,站起身) 你們慢用。我先去忙了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "精靈女孩優雅地點了點頭,然後轉身離開。恵美繼續攪拌著鍋裡的食物,一股香氣飄了出來。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(開心地) 李杰先生,要一起吃嗎?我煮了一些粥,還加了精靈姐姐給的香草和蘑菇。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心獨白) 糟糕...我剛才已經吃了麵包了...但是看她這麼開心的樣子,怎麼好意思拒絕..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(微笑著坐下) 好啊。其實我剛才只是隨便吃了點麵包,還不太飽。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這不完全是謊言。那幾塊乾硬的麵包確實沒讓他吃飽,而且現在聞到粥的香味,他發現自己確實還有胃口。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(高興地盛了兩碗粥) 太好了!我做了很多,就怕你不餓。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人端著碗,走到湖邊坐下。銀月湖的湖面依然平靜如鏡,倒映著天空中的雙月和星辰。發光的花朵在水面上輕輕搖曳,空氣中瀰漫著清新的花香和粥的香味。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰嚐了一口,粥煮得軟糯可口,香草和蘑菇的味道恰到好處,比他想像中好吃多了。恵美一邊吃一邊偷偷看著他的表情,看到他吃得津津有味,臉上露出了滿足的笑容。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(由衷地) 很好吃。妳手藝真不錯。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(開心得眼睛都彎了起來) 真的嗎?太好了!我還怕煮壞了..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人就這樣坐在湖邊,靜靜地享用著這頓簡單的早餐。周圍偶爾傳來精靈們的交談聲和孩子們的笑聲,一切都顯得如此和平而溫馨。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "吃完飯後,李杰將碗放在一邊,轉頭看向恵美。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "清水,我剛才去找艾拉如先生了。有個好消息要告訴妳。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(眼睛一亮) 好消息?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "艾拉如先生說,他已經聯繫上他的兒子了。他兒子告訴他回到我們世界的方法。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰本以為恵美會表現得很激動,但她的反應卻出乎他的意料。恵美臉上確實露出了笑容,眼中也閃爍著喜悅,但那種喜悅更像是...一種確認?而不是意外的驚喜。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(微笑著,語氣平靜) 那太好了。艾拉如先生說要怎麼做呢?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "我們需要去一個叫「終焉祭壇」的地方。那是古代精靈王國的遺址,有可以把人送回原本世界的技術。不過在那之前,我們要先去接受一個精靈儀式,讓神樹認可我們。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(點點頭,表情依然平靜) 嗯...原來是這樣啊...那我們什麼時候去?" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著恵美平靜的反應,心中閃過一絲疑惑。這麼重要的消息,她怎麼...好像早就知道一樣?一點都不意外?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(試探性地問) 清水...妳...好像不太驚訝?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(愣了一下,然後微笑) 啊...是嗎?可能...可能是因為我一直相信一定有辦法回去吧。所以聽到確切的方法,就覺得...嗯,果然如此的感覚?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心獨白) 是這樣嗎...還是她只是比較樂觀..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰想了想,決定不再追問。或許她只是個天生樂觀的人,或許她對這種事情有著不同尋常的直覺。無論如何,現在有了回家的方法,這才是最重要的。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "艾拉如先生說我們不用急,可以在這裡多休息幾天。村民們也需要時間整頓,他也要準備儀式用的東西。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(眼睛亮了起來) 那...我們可以在這裡多待一陣子嗎?這裡好美,精靈們也都很友善..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(想了想) 不如...我們在這裡休息五天吧。第五天再出發前往神樹。這樣既能好好休息,也不會耽誤太久。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(開心地拍了拍手) 好啊!五天的話,我們可以好好享受這裡的美景!" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(微笑) 是啊。難得有機會在這麼美的地方休息,就當是...意外的假期吧。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "那就這麼說定了!第五天我們就出發!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這樣,李杰和恵美決定在銀月湖畔多停留幾天。這是他們來到這個世界後,第一次能真正放鬆下來享受平靜的時光。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一天,一個精靈老人教他們如何用湖邊的蘆葦編織籃子。老人的手指靈巧地穿梭在蘆葦之間,李杰笨拙地模仿著,編出來的籃子歪歪扭扭的,惹得老人哈哈大笑。恵美倒是很有天分,她編出的籃子雖然簡單,但形狀工整,連老人都誇獎她手巧。" },
    { characterId: CharacterId.Elf, character: "精靈老人", dialogue: "(笑著) 小姑娘很有天賦啊。要不要試試更複雜的花紋?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(興奮地) 好啊!麻煩您教我!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著恵美專注學習的樣子,心中湧起一股溫暖。在這個陌生的世界裡,能有這樣平靜的時刻,實在是難得的幸福。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二天,幾個精靈孩子邀請他們一起玩遊戲。孩子們圍成一圈,用一種發光的小球進行傳遞遊戲。小球在誰手上停留太久,就會發出清脆的鈴聲,那個人就算輸了。" },
    { characterId: CharacterId.Elf, character: "精靈孩子", dialogue: "(笑著) 清水姐姐,接住!" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(慌張地接住球) 啊!來了來了!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "恵美的反應總是慢半拍,經常讓球在手上鈴聲大作,逗得孩子們咯咯直笑。李杰站在一旁看著,忍不住也跟著笑了起來。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(笑著說) 清水,妳的反應也太慢了吧。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(臉紅了,嘟著嘴) 李杰先生不要光笑!你來試試看啊!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "結果李杰加入遊戲後,表現得比恵美還糟糕,惹得所有人都笑彎了腰。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三天傍晚——雖然這個世界沒有真正的傍晚,但精靈們似乎有自己的作息規律——村民們在湖邊舉行了一個小型的聚會。他們圍坐在營火旁,分享著食物和故事。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一位年邁的精靈吟遊詩人拿起一把古老的豎琴,開始彈奏優美的樂曲。樂聲在夜空中飄蕩,如同銀色的月光般柔和。幾個年輕的精靈隨著音樂翩翩起舞,他們的動作優雅而流暢,裙擺和長髮在空中劃出美麗的弧線。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看得入神,小聲對李杰說) 好美...他們跳得好美..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(點點頭) 是啊...感覺就像在看一場夢境..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個精靈少女走過來,伸手邀請恵美一起跳舞。恵美害羞地搖搖頭,但在少女的再三邀請下,還是站了起來。她笨拙地跟著精靈們的動作,雖然不如他們優雅,但那份認真和投入讓她看起來格外動人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰坐在營火旁,看著恵美在月光下舞動的身影,心中湧起一股難以名狀的情緒。這個女孩,從他們第一次在月台相遇,到現在一起經歷這麼多事情...不知不覺間,她已經在他心中佔據了一個特別的位置。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四天,艾拉如帶他們參觀了精靈們重建的臨時工作坊。精靈工匠們正在用湖邊的木材和石頭製作各種工具和器具。他們的技藝精湛,即使是最簡單的木碗,在他們手中也能雕刻出精美的花紋。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(對李杰說) 我們精靈族雖然經歷了這次災難,但只要大家還在一起,就能重建一切。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(由衷地) 你們真的很堅強。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(微笑) 這就是生命的韌性。無論經歷什麼,只要還有希望,就能繼續前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這些話深深地觸動了李杰。他想起自己在現實世界裡那些煩惱和壓力,突然覺得那些都變得微不足道了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這樣,四天的時間在平靜而美好的氛圍中悄然流逝。雖然這個世界依然籠罩在永恆的夜色中,雖然他們依然身處險境,但這幾天的經歷,卻成為了他們記憶中最珍貴的片段。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰和恵美學會了編織籃子,學會了精靈的簡單歌謠,品嚐了各種奇特的精靈料理,聽了無數關於古代精靈王國的傳說故事。他們和精靈們建立了深厚的友誼,這個曾經陌生而恐怖的世界,逐漸在他們心中變得溫暖起來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "到了第五天,李杰和恵美一早就開始收拾行裝。按照他們第一天的約定,今天就是出發的日子。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "恵美將這幾天精靈們送給她的小禮物——一個精緻的編織籃子、幾朵會發光的乾燥花、還有一條繡著精靈文字的絲巾——小心翼翼地收進背包裡。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看著這些禮物,眼眶有些濕潤) 真捨不得離開這裡..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(整理著帳篷,溫和地說) 是啊。但我們該出發了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "收拾完行李後,兩人一起走到湖邊,最後一次欣賞銀月湖的美景。平靜的湖面倒映著雙月和星辰,發光的花朵在水面上輕輕搖曳,一切都和他們剛來時一樣寧靜而美麗。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(深吸一口氣) 我會永遠記得這裡的。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(點點頭) 我也是。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "艾拉如已經在村口等候他們。他身旁站著幾位精靈長者,還有這幾天和他們相處融洽的精靈村民們。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(微笑著) 準備好了嗎?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(鄭重地點頭) 是的。我們準備好了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "精靈村民們紛紛上前,與他們道別。那位教恵美編織的老人、和他們一起玩遊戲的孩子們、還有那位彈奏豎琴的吟遊詩人...每個人都給予了他們真誠的祝福。" },
    { characterId: CharacterId.Elf, character: "精靈老人", dialogue: "(拉著恵美的手) 孩子,願神樹的光芒照亮你的歸途。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(眼淚終於忍不住流下來) 謝謝您...謝謝大家..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在精靈們的目送下,李杰和恵美跟著艾拉如離開了銀月湖畔的臨時村落。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們即將前往神樹,接受精靈的祝福,然後踏上前往終焉祭壇的旅程——那個能讓他們回家的地方。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這段在銀月湖畔的短暫時光,將永遠留在他們的記憶中,成為這段奇異旅程中最溫暖的一頁。" },
];
